#include <bits/stdc++.h>
using namespace std;
const int N=100005,mod=998244353;
#define ll long long
ll n,m,q,cnt[N],a[N],op[N],b[N],add[N],pos[N];//b :  num*?
vector<int> g[N],fan[N];

int vis[N];// for topo
void topo1()
{
	queue<int> q;
	for(int i=0;i<=m;i++)
	{
		vis[i]=fan[i].size();
		if(vis[i]==0) q.push(i);
	}
	while(!q.empty())
	{
		int u=q.front();
		q.pop();
		for(int i=0;i<g[u].size();i++)
		{
			int v=g[u][i];
//			cout<<u<<" -> "<<v<<"  "<<b[u]<<"\n";
			b[v]=b[v]*b[u]%mod;
			vis[v]--;
			if(vis[v]==0) q.push(v);
		}
	}

}

void topo2()
{
	queue<int> q;
	for(int i=0;i<=m;i++)
	{
		vis[i]=g[i].size();
		if(vis[i]==0) q.push(i);
	}
	while(!q.empty())
	{
		ll tmp=1;
		int u=q.front();
		q.pop();
		for(int i=fan[u].size()-1;i>=0;i--)
		{
			int v=fan[u][i];
			cnt[v]=(cnt[v]+cnt[u]*tmp)%mod;
			tmp=tmp*b[v]%mod;
			vis[v]--;
			if(vis[v]==0) q.push(v);
		}
	}
}
int main()
{
//	freopen("call3.in","r",stdin);
//	freopen("call3.out","w",stdout);
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	b[0]=1;
	cnt[0]=1;
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
	}
	cin>>m;
	for(int i=1;i<=m;i++)
	{
		cin>>op[i];
		b[i]=1;
		if(op[i]==1)
		{
			cin>>pos[i]>>add[i];
		}
		else if(op[i]==2)
		{
			cin>>b[i];
		}
		else
		{
			int x;
			cin>>x;
			for(int j=1;j<=x;j++)
			{
				int v;
				cin>>v;
				g[v].push_back(i);
				fan[i].push_back(v);
			}
		}
	}
	cin>>q;
	for(int i=1;i<=q;i++)
	{
		int x;
		cin>>x;
		fan[0].push_back(x);
		g[x].push_back(0);
	}
//	for(int i=0;i<=n;i++)
//	{
//		cout<<i<<"  ->\n";
//		for(int j=0;j<g[i].size();j++)
//		{
//			int v=g[i][j];
//			cout<<v<<" ";
//		}
//		cout<<endl;
//	}
	topo1();
//	cout<<"aaa"<<endl;
	topo2();
	for(int i=0;i<=n;i++)
	{
		a[i]=a[i]*b[0]%mod;
//		cout<<b[i]<<" "<<cnt[i]<<"aa\n";
	}
	for(int i=1;i<=m;i++)
	{
		if(op[i]==1)
		{
			a[pos[i]]=(a[pos[i]]+cnt[i]*add[i])%mod;
		}
	}
	for(int i=1;i<=n;i++)
	{
		cout<<a[i]<<" ";
	}
	return 0;
}

